const { GoogleGenAI } = require\('@google/genai'\);
const fs = require\('fs'\);

const ai = new GoogleGenAI\({ apiKey: process.env.GEMINI_API_KEY }\);

async function generate\(\) {
  const refImage = fs.readFileSync\('me.jpg'\);
  const base64 = refImage.toString\('base64'\);

  console.log\('Generating hero image...'\);
  const response = await ai.models.generateContent\({
    model: 'gemini-3-pro-image-preview',
    contents: [
      {
        text: 'Create a cinematic, wide-angle hero portrait of this person for a website hero section. He should be positioned on the right side of the frame, looking slightly off-camera with a confident, thoughtful expression. The environment should be a modern, minimal workspace or architectural space with clean geometric lines. The overall color palette must be: deep black \(#111111\) tones dominating, warm beige/paper \(#E8E4DD\) ambient light, and subtle signal-red \(#E63B2E\) accent — perhaps a thin red neon line, a red element in the background, or red-tinted rim lighting on one side. The mood is editorial, cinematic, and premium. Shallow depth of field. The left side of the image should be darker/emptier to allow text overlay. Dramatic but minimal lighting. No text.'
      },
      {
        inlineData: {
          mimeType: 'image/jpeg',
          data: base64
        }
      }
    ],
    config: {
      responseModalities: ['TEXT', 'IMAGE'],
      imageConfig: { aspectRatio: '16:9', imageSize: '4K' },
    },
  }\);

  for \(const part of response.candidates[0].content.parts\) {
    if \(part.text && !part.thought\) {
      console.log\('Model text:', part.text\);
    }
    if \(part.inlineData && !part.thought\) {
      const buffer = Buffer.from\(part.inlineData.data, 'base64'\);
      fs.writeFileSync\('public/hero-bg.jpg', buffer\);
      console.log\('Saved hero-bg.jpg \(' + buffer.length + ' bytes\)'\);
    }
  }
}

generate\(\).catch\(e => console.error\(e\)\);
" 2>&1)

